SELECT br.*, u.username AS join_username, b.title AS join_book_title, b.isbn AS join_book_isbn FROM borrow_record br LEFT JOIN sys_user u ON br.user_id = u.id LEFT JOIN book b ON br.book_id = b.id WHERE br.user_id = #{userId} AND br.deleted = 0
AND br.status = #{status}
ORDER BY br.create_time DESC

